const jwt = require('jsonwebtoken');
const express = require('express');
const app = express();

// The secret key should be secured and not exposed like this.
const SECRET_KEY = 'your-secret-key';

function authenticateToken(req, res, next) {
    const authHeader = req.headers.authorization;
    const token = authHeader && authHeader.split(' ')[1];

    if (token == null) return res.sendStatus(401); // if token doesn't exist, access is unauthorized

    jwt.verify(token, SECRET_KEY, (err, user) => {
        if (err) return res.sendStatus(403); // if token is incorrect, access is forbidden
        req.user = user; // store user info in request
        next(); // pass to the next middleware
    });
}

app.use(authenticateToken);

